inline std::string toString(StandardIdentityEnum v) {
    switch (v) {
        case StandardIdentityEnum::Unspecified: return "STANDARD_IDENTITY_ENUM_UNSPECIFIED";
        case StandardIdentityEnum::Pending: return "STANDARD_IDENTITY_ENUM_PENDING";
        case StandardIdentityEnum::Unknown: return "STANDARD_IDENTITY_ENUM_UNKNOWN";
        case StandardIdentityEnum::AssumedFriend: return "STANDARD_IDENTITY_ENUM_ASSUMED_FRIEND";
        case StandardIdentityEnum::Friend: return "STANDARD_IDENTITY_ENUM_FRIEND";
        case StandardIdentityEnum::Neutral: return "STANDARD_IDENTITY_ENUM_NEUTRAL";
        case StandardIdentityEnum::Suspect: return "STANDARD_IDENTITY_ENUM_SUSPECT";
        case StandardIdentityEnum::Hostile: return "STANDARD_IDENTITY_ENUM_HOSTILE";
        case StandardIdentityEnum::Undefined: return "STANDARD_IDENTITY_ENUM_UNDEFINED";
    }
    return "STANDARD_IDENTITY_ENUM_UNSPECIFIED";
}
inline StandardIdentityEnum standardIdentityEnumFromString(const std::string& s) {
    if (s == "STANDARD_IDENTITY_ENUM_UNSPECIFIED") return StandardIdentityEnum::Unspecified;
    if (s == "STANDARD_IDENTITY_ENUM_PENDING") return StandardIdentityEnum::Pending;
    if (s == "STANDARD_IDENTITY_ENUM_UNKNOWN") return StandardIdentityEnum::Unknown;
    if (s == "STANDARD_IDENTITY_ENUM_ASSUMED_FRIEND") return StandardIdentityEnum::AssumedFriend;
    if (s == "STANDARD_IDENTITY_ENUM_FRIEND") return StandardIdentityEnum::Friend;
    if (s == "STANDARD_IDENTITY_ENUM_NEUTRAL") return StandardIdentityEnum::Neutral;
    if (s == "STANDARD_IDENTITY_ENUM_SUSPECT") return StandardIdentityEnum::Suspect;
    if (s == "STANDARD_IDENTITY_ENUM_HOSTILE") return StandardIdentityEnum::Hostile;
    if (s == "STANDARD_IDENTITY_ENUM_UNDEFINED") return StandardIdentityEnum::Undefined;
    return StandardIdentityEnum::Unspecified;
}
